import{_ as a,g as o,h as e,U as s}from"./chunks/vitepress-theme-teek.CqY1sKvl.js";const A=JSON.parse('{"title":"读后感：AI 原生时代的复合型人才，究竟需要怎样的特质？","description":"摘要总结：本文结合保罗・格雷厄姆《How to Do Great Work》核心观点，探讨 AI 原生时代复合型人才的核心特质。AI 让基础执行能力快速贬值，人才的核心壁垒不再是解决问题，而是提出优质问题、培养非共识品味。同时需坚守智力诚实，拥有打破常规的创新勇气，借助 AI 放大个人成长杠杆，以小切口实践实现指数级成长。人类独有的好奇心，是突破 AI 平庸、取得杰出成就的最终底气。","frontmatter":{"date":"2024-06-15T22:23:00.000Z","title":"读后感：AI 原生时代的复合型人才，究竟需要怎样的特质？","description":"摘要总结：本文结合保罗・格雷厄姆《How to Do Great Work》核心观点，探讨 AI 原生时代复合型人才的核心特质。AI 让基础执行能力快速贬值，人才的核心壁垒不再是解决问题，而是提出优质问题、培养非共识品味。同时需坚守智力诚实，拥有打破常规的创新勇气，借助 AI 放大个人成长杠杆，以小切口实践实现指数级成长。人类独有的好奇心，是突破 AI 平庸、取得杰出成就的最终底气。","coverImg":"/img/cover/product_sense_bg.png","permalink":"/product-sense/ai-native-composite-talents","categories":["产品 Sense"],"tags":["AI","成长"]},"headers":[],"relativePath":"10.产品 Sense/02.新 T 型人/20.读后感：AI 原生时代的复合型人才，究竟需要怎样的特质？.md","filePath":"10.产品 Sense/02.新 T 型人/20.读后感：AI 原生时代的复合型人才，究竟需要怎样的特质？.md"}'),r={name:"10.产品 Sense/02.新 T 型人/20.读后感：AI 原生时代的复合型人才，究竟需要怎样的特质？.md"};function i(l,t,p,n,c,d){return e(),o("div",null,[...t[0]||(t[0]=[s('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /10.产品 Sense/02.新 T 型人/20.读后感：AI 原生时代的复合型人才，究竟需要怎样的特质？.md for this page in Markdown format</div><h1 id="读后感-ai-原生时代的复合型人才-究竟需要怎样的特质" tabindex="-1">读后感：AI 原生时代的复合型人才，究竟需要怎样的特质？ <a class="header-anchor" href="#读后感-ai-原生时代的复合型人才-究竟需要怎样的特质" aria-label="Permalink to “读后感：AI 原生时代的复合型人才，究竟需要怎样的特质？”">​</a></h1><blockquote><p><strong>原文标题</strong>：《How to Do Great Work》（如何取得杰出成就）</p><p><strong>原文地址</strong>：<a href="https://paulgraham.com/greatwork.html" target="_blank" rel="noreferrer">https://paulgraham.com/greatwork.html</a></p><p><strong>原文作者</strong>：Paul Graham（保罗·格雷厄姆），硅谷顶级孵化器 Y Combinator 创始人，被誉为“硅谷创业教父”，也是经典技术哲学著作《黑客与画家》的作者。</p><p><strong>文章背景</strong>：原文是保罗·格雷厄姆之前准备了半年之久的重磅长文，他试图讲明白一个适用于每个人的主题——如何做成「大事」（great work）。通读全文，你会发现，这是一篇非常实用的工作指南，并且其中的许多内容，都与AI原生时代的复合型人才所需要具备的特质非常一致。</p></blockquote><h2 id="_1-引言-当-执行-被-ai-填平-什么才是核心壁垒" tabindex="-1">1. 引言：当“执行”被 AI 填平，什么才是核心壁垒？ <a class="header-anchor" href="#_1-引言-当-执行-被-ai-填平-什么才是核心壁垒" aria-label="Permalink to “1. 引言：当“执行”被 AI 填平，什么才是核心壁垒？”">​</a></h2><p>通读保罗·格雷厄姆（以下简称 PG）这篇两万字的长文，笔者最大的感受是：这不仅是一份跨越领域的“伟大成就指南”，更是一份为 AI 原生时代量身定制的“复合型人才生存手册”。</p><p>在 AI 爆发的当下，写代码、画图、撰写基础文案甚至简单的数据分析，这些曾经被视为专业技能的“执行动作”，正在迅速贬值。当 AI 把“解答问题”的门槛降到极低时，人与人之间的差距将被什么拉开？</p><p>PG 在文章中给出了答案：<strong>找到正确的问题、保持非共识的好奇心、以及拥有极高的品味</strong>。以下是我结合 AI 时代浪潮，对文章核心观点的梳理与个人思考。</p><h2 id="_2-从-解决问题-到-发现问题-提问力决定生产力" tabindex="-1">2. 从“解决问题”到“发现问题”：提问力决定生产力 <a class="header-anchor" href="#_2-从-解决问题-到-发现问题-提问力决定生产力" aria-label="Permalink to “2. 从“解决问题”到“发现问题”：提问力决定生产力”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">【原文精髓】</p><p><strong>“问题不仅导向答案，而且也导向更多的问题。”</strong></p><p>PG 认为，人们在解决问题上表现出的原创性，远超在“决定解决哪些问题”上。很多人被困在时髦的漩涡里，而真正杰出的成就往往始于敏锐地注意到了知识边缘的“缺口”。</p></div><div class="note custom-block"><p class="title note-title custom-block-title">【我的体会】</p><p>在 AI 时代，这句话被赋予了史无前例的现实意义。大模型（LLM）本质上是一个超级“解答机”，它极其擅长顺着你给定的逻辑生成答案。这意味着，<strong>在未来，寻找答案的能力将不再稀缺，稀缺的是提出绝佳问题的能力</strong>。</p><p>一个 AI 原生时代的复合型人才，其核心特质就是成为一个高阶的“问题发现者”。我们需要利用 AI 快速跨越多个领域的知识盲区（即 PG 说的“到达领域前沿”），然后在前沿地带敏锐地嗅到那些被主流忽视的空白。&quot;Prompt（提示词）质量&quot;在某种程度上正是我们洞察力与品味的直接映射——它决定了我们能否从 AI 这座&quot;超级解答机&quot;中，挖掘出真正有价值的答案。</p></div><h2 id="_3-培养非共识的-品味-逃离-ai-生成的-平均数" tabindex="-1">3. 培养非共识的“品味”：逃离 AI 生成的“平均数” <a class="header-anchor" href="#_3-培养非共识的-品味-逃离-ai-生成的-平均数" aria-label="Permalink to “3. 培养非共识的“品味”：逃离 AI 生成的“平均数””">​</a></h2><div class="tip custom-block"><p class="custom-block-title">【原文精髓】</p><p>PG 强调：“有意识地培养对自己领域工作的品味。除非我们知道什么是最好的，以及是什么使它成为最好的，否则我们并不知道自己在追求什么。”</p></div><div class="note custom-block"><p class="title note-title custom-block-title">【我的体会】</p><p>在这个信息大爆炸的时代，AI 正在批量生产海量的、无差别的“及格线以上”的内容与代码，这带来了两个极端的现象：</p><ul><li><p><strong>下限被拔高了</strong>，平庸者可以利用 AI 瞬间看起来像个专家。</p></li><li><p><strong>上限变得更难突破了</strong>，因为所有由 AI 生成的东西，本质上都是在“历史数据的平均值”上做微小变异。</p></li></ul><p>这就使得 PG 提到的“品味（Taste）”变得无比重要。复合型人才必须拥有极高的审美眼光与判别能力，这种能力无法通过算法习得。当我们面对 AI 给出的多个解决方案时，需要敏锐地判断哪个方案不仅可行，而且足够“优雅”。<strong>品味，将成为我们在 AI 自动驾驶浪潮中把稳方向盘的核心资产</strong>。</p></div><h2 id="_4-保持真诚与-打破规则-的勇气-抵抗-ai-的-幻觉-与平庸" tabindex="-1">4. 保持真诚与“打破规则”的勇气：抵抗 AI 的“幻觉”与平庸 <a class="header-anchor" href="#_4-保持真诚与-打破规则-的勇气-抵抗-ai-的-幻觉-与平庸" aria-label="Permalink to “4. 保持真诚与“打破规则”的勇气：抵抗 AI 的“幻觉”与平庸”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">【原文精髓】</p><p>“要找到新的想法，就必须抓住不合理的迹象，而不是避而不见。” PG 在文章中反复强调独立思考（无论是主动还是被动的）与真诚（Intellectual Honesty，智力诚实）的力量。一个好的新想法，一开始往往是不受待见的。</p></div><div class="note custom-block"><p class="title note-title custom-block-title">【我的体会】</p><p>大模型是基于“人类现有共识（语料库）”训练出来的产物，这也意味着如果只依赖 AI 的输出，我们将永远在已知的舒适区内打转。<strong>真正“伟大”的创新，必然是对现有常识的颠覆与补充。</strong></p><p>这就要求<strong>复合型人才必须具备极度的“智力诚实”</strong>。我们要把 AI 当作工具去验证假设，但在 AI 给出看似完美的常规解答时，我们要敢于说：“不，这里还有缺陷。”</p><p>当所有人都沉浸在某种热门技术或框架中时，我们要敢于像 PG 说的那样，选择冷门但具有极大潜力的“问题空间”。在 AI 时代，你的原创性，恰恰体现在你敢于在 AI 给出“标准答案”时，按下暂停键，去追问一个看似疯狂但属于“正确类别”的问题。</p></div><h2 id="_5-复合指数增长-以小见大的行动力" tabindex="-1">5. 复合指数增长：以小见大的行动力 <a class="header-anchor" href="#_5-复合指数增长-以小见大的行动力" aria-label="Permalink to “5. 复合指数增长：以小见大的行动力”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">【原文精髓】</p><p>“指数增长的问题在于曲线在开始时给人的感觉很平，但它不是。” PG 指出：杰出成就的累积效应是被严重低估的，关键在于一致性。同时，我们不需要做庞大的计划，只需要做“可能有用的最简单的东西”，并在实践中不断演化。</p></div><div class="note custom-block"><p class="title note-title custom-block-title">【我的体会】</p><p>在这一节，PG 的观点与“敏捷开发”不谋而合。但在今天，有了 AI 加持，个人开发者的“复合杠杆率”被无限放大了。</p><p>过去，打造一个最小可行性产品（MVP）往往需要数周时间。如今，在 AI 编程工具的助力下，一个具备复合能力的人才或许只需一个周末就能完成原型的搭建与验证。这意味着<strong>&quot;以项目为单位的拖延&quot;在当下变得愈发不可承受</strong>。</p><p>AI 时代的复合型人才，不再是拥有单一深厚技能的螺丝钉，而是能够一人承担“产品经理 + 全栈工程师 + 运营”角色的超级个体。一旦找到那个令你产生深度兴趣的切入点，并持续深耕，你的成长曲线将在极短时间内迎来惊人的指数级跃升。</p></div><h2 id="_6-在算力面前保持敬畏-在机器面前保持好奇" tabindex="-1">6. 在算力面前保持敬畏，在机器面前保持好奇 <a class="header-anchor" href="#_6-在算力面前保持敬畏-在机器面前保持好奇" aria-label="Permalink to “6. 在算力面前保持敬畏，在机器面前保持好奇”">​</a></h2><p>通读 PG 这篇万字长文，如果要问：在这个技术天翻地覆的时代，取得成就究竟有什么不可替代的秘诀？文章给出的最终答案是——好奇心。</p><p>AI 可以模仿语气，可以生成代码，可以计算概率，却无法拥有真正自发的好奇心。它不会为一个微小的不合理现象而抓狂，也不会为了一个未知的答案彻夜难眠。</p><p>这正是我们作为人类最后的底牌。去追寻那些让你兴奋不已、让你&quot;过分&quot;好奇的问题吧——借助 AI 的算力跨越执行的鸿沟，以极高的品味去甄别筛选，用不妥协的真诚去深入探索。</p><p>剩下的，正如保罗·格雷厄姆所说：&quot;还有很多发现正等待着被发现，为什么不由我们自己去发现呢？&quot;</p>',24)])])}const I=a(r,[["render",i]]);export{A as __pageData,I as default};
